const express = require('express');
const session = require('express-session');
const axios = require('axios');
const jwt = require('jsonwebtoken');
const jwksClient = require('jwks-rsa');
const crypto = require('crypto');

const app = express();

const OIDC_CONFIG = {
  issuer: process.env.OIDC_ISSUER,
  clientId: process.env.OIDC_CLIENT_ID,
  clientSecret: process.env.OIDC_CLIENT_SECRET,
  redirectUri: process.env.OIDC_REDIRECT_URI,
  jwksUri: process.env.OIDC_JWKS_URI
};

const jwksClientInstance = jwksClient({
  jwksUri: OIDC_CONFIG.jwksUri,
  cache: true,
  cacheMaxAge: 86400000,
  rateLimit: true,
  jwksRequestsPerMinute: 10
});

function getKey(header, callback) {
  jwksClientInstance.getSigningKey(header.kid, (err, key) => {
    if (err) {
      callback(err);
      return;
    }
    const signingKey = key.getPublicKey();
    callback(null, signingKey);
  });
}

function verifyIdToken(idToken) {
  return new Promise((resolve, reject) => {
    jwt.verify(
      idToken,
      getKey,
      {
        algorithms: ['RS256'],
        issuer: OIDC_CONFIG.issuer,
        audience: OIDC_CONFIG.clientId,
        clockTolerance: 60
      },
      (err, decoded) => {
        if (err) {
          reject(err);
        } else {
          resolve(decoded);
        }
      }
    );
  });
}

app.use(session({
  secret: process.env.SESSION_SECRET,
  resave: false,
  saveUninitialized: false,
  cookie: {
    secure: true,
    httpOnly: true,
    sameSite: 'lax',
    maxAge: 3600000
  }
}));

app.get('/login', (req, res) => {
  const state = crypto.randomBytes(32).toString('hex');
  const nonce = crypto.randomBytes(32).toString('hex');
  
  req.session.oauthState = state;
  req.session.oauthNonce = nonce;
  
  const authUrl = `${OIDC_CONFIG.issuer}/authorize?` +
    `response_type=code&` +
    `client_id=${encodeURIComponent(OIDC_CONFIG.clientId)}&` +
    `redirect_uri=${encodeURIComponent(OIDC_CONFIG.redirectUri)}&` +
    `scope=openid%20profile%20email&` +
    `state=${state}&` +
    `nonce=${nonce}`;
  
  res.redirect(authUrl);
});

app.get('/callback', async (req, res) => {
  try {
    const { code, state } = req.query;
    
    if (!code || !state) {
      return res.status(400).send('Missing parameters');
    }
    
    if (state !== req.session.oauthState) {
      return res.status(403).send('Invalid state parameter');
    }
    
    delete req.session.oauthState;
    const nonce = req.session.oauthNonce;
    delete req.session.oauthNonce;
    
    const tokenResponse = await axios.post(
      `${OIDC_CONFIG.issuer}/token`,
      new URLSearchParams({
        grant_type: 'authorization_code',
        code: code,
        redirect_uri: OIDC_CONFIG.redirectUri,
        client_id: OIDC_CONFIG.clientId,
        client_secret: OIDC_CONFIG.clientSecret
      }),
      {
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded'
        }
      }
    );
    
    const { id_token, access_token } = tokenResponse.data;
    
    const claims = await verifyIdToken(id_token);
    
    if (claims.nonce !== nonce) {
      return res.status(403).send('Invalid nonce');
    }
    
    req.session.user = {
      sub: claims.sub,
      email: claims.email,
      name: claims.name,
      picture: claims.picture
    };
    
    req.session.accessToken = access_token;
    
    res.redirect('/dashboard');
  } catch (error) {
    console.error('Authentication error:', error.message);
    res.status(500).send('Authentication failed');
  }
});

app.get('/dashboard', (req, res) => {
  if (!req.session.user) {
    return res.redirect('/login');
  }
  res.json({ user: req.session.user });
});

app.get('/logout', (req, res) => {
  req.session.destroy();
  res.redirect('/');
});

app.listen(3000);